import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Header from './components/entete/header';
import Footer from './components/footer/footer';
import HomePage from './pages/homePage';
import QuiJeSuis from './pages/pageQjs';
import MesServices from './pages/services';
import Competences from './pages/competences/competences'; // Utilisez directement le composant Competences, pas Grid
import MesProjets from './pages/projets';

const App = () => {
  return (
    <Router>
      <Header />
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/pageQjs" element={<QuiJeSuis />} />
        <Route path="/services" element={<MesServices />} />
        <Route path="/competences" element={<Competences />} />
        <Route path="/projets" element={<MesProjets />} />
      </Routes>
      <Footer />
    </Router>
  );
};

export default App;
